<template>
	<view class="template-order tn-safe-area-inset-bottom">
		<!-- еҜјиҲӘж Ҹй«ҳеәҰеҚ дҪҚпјҲйҖӮй…ҚдёҚеҗҢи®ҫеӨҮпјү -->
		<view class="nav-placeholder" :style="{height: vuex_custom_bar_height + 'px'}"></view>

		<!-- и®ўеҚ•е®№еҷЁ -->
		<view class="order__container">
			<!-- йЎ¶йғЁж Үзӯҫж Ҹ -->
			<view class="tn-bg-white order__tabs-wrap">
				<tn-tabs-swiper class="order__tabs" ref="tabs" activeColor="#3165CC" inactiveColor="#080808"
					:list="list" :current="tabsIndex" :isScroll="false" @change="tabsChange">
				</tn-tabs-swiper>
			</view>

			<!-- ж ҮзӯҫеҶ…е®№еҢәеҹҹ - Swiper -->
			<swiper class="order__swiper" :current="swiperIndex" @transition="swiperTransition"
				@animationfinish="swiperAnimationFinish">
				<!-- иҝӣиЎҢдёӯи®ўеҚ• -->
				<swiper-item class="order__swiper__item">
					<scroll-view scroll-y class="order__scroll-view" :style="{height: scrollViewHeight + 'px'}">
						<!-- з©әж•°жҚ®жҸҗзӨә -->
						<view v-if="ongoingRepairs.length === 0" class="empty-data">
							<view class="tn-text-center" style="font-size: 120rpx; color: #ccc; padding: 40rpx 0;">
								<text class="tn-icon-bill tn-color-gray--light"></text>
							</view>
							<view class="tn-color-gray--disabled tn-text-center tn-text-lg">жҡӮж— иҝӣиЎҢдёӯзҡ„жҠҘдҝ®еҚ•</view>
						</view>

						<!-- иҝӣиЎҢдёӯи®ўеҚ•еҲ—иЎЁ -->
						<view v-for="(item,index) in ongoingRepairs" :key="index" class="order__item"
							@click="tn('./order_details/order_details?id=' + item.id)">
							<view
								class="order__item__head tn-flex tn-flex-direction-row tn-flex-col-center tn-flex-row-between">
								<view class="order__item__head__title">жҠҘдҝ®еҚ•еҸ·пјҡ{{ item.id }}</view>
							</view>

							<view
								class="order__item__content tn-flex tn-flex-direction-row tn-flex-nowrap tn-flex-col-center tn-flex-row-center">
								<view class="order__item__content__image" style="margin-left: -10px;">
									<image src="/static/tabbar/i2.png" mode="aspectFill"></image>
								</view>
								<view class="order__item__content__title">
									<text
										class="order__item__content__info__price__cons">жҠҘдҝ®зұ»еһӢпјҡ{{ item.repairClass || 'жңӘзҹҘзұ»еһӢ' }}</text>
									<br>
									<text
										class="order__item__content__info__price__cons">ж•…йҡңжҸҸиҝ°пјҡ{{ item.note || 'ж— жҸҸиҝ°' }}</text>
									<br>
									<text
										class="order__item__content__info__price__cons">жҠҘдҝ®ж—¶й—ҙпјҡ{{ item.time || 'жңӘзҹҘж—¶й—ҙ' }}</text>
								</view>
							</view>

							<view
								class="order__item__operation tn-flex tn-flex-direction-row tn-flex-nowrap tn-flex-col-center tn-flex-row-between">
								<view class="order__item__operaation__left">
									<text class="order__item__operaation__left--text"></text>
								</view>
								<view
									class="order__item__operation__right tn-flex tn-flex-direction-row tn-flex-nowrap tn-flex-col-center tn-flex-row-right">
									<view class="order__item__operation__right__button">
										<tn-button shadow shape="round" fontColor="tn-color-white"
											backgroundColor="tn-bg-blue" :fontSize="24" height="auto"
											padding="10rpx 18rpx">
											жҹҘзңӢиҜҰз»Ҷ</tn-button>
									</view>
								</view>
							</view>
						</view>
						<!-- еә•йғЁе®үе…Ёи·қзҰ» -->
						<view class="tn-padding-bottom"></view>
					</scroll-view>
				</swiper-item>

				<!-- е·Іе®ҢжҲҗи®ўеҚ• -->
				<swiper-item class="order__swiper__item">
					<scroll-view scroll-y class="order__scroll-view" :style="{height: scrollViewHeight + 'px'}">
						<!-- з©әж•°жҚ®жҸҗзӨә -->
						<view v-if="completedRepairs.length === 0" class="empty-data">
							<view class="tn-text-center" style="font-size: 120rpx; color: #ccc; padding: 40rpx 0;">
								<text class="tn-icon-bill tn-color-gray--light"></text>
							</view>
							<view class="tn-color-gray--disabled tn-text-center tn-text-lg">жҡӮж— е·Іе®ҢжҲҗзҡ„жҠҘдҝ®еҚ•</view>
						</view>

						<!-- е·Іе®ҢжҲҗи®ўеҚ•еҲ—иЎЁ -->
						<view v-for="(item,index) in completedRepairs" :key="index" class="order__item"
							@click="tn('./order_details/order_details?id=' + item.id)">
							<view
								class="order__item__head tn-flex tn-flex-direction-row tn-flex-col-center tn-flex-row-between">
								<view class="order__item__head__title">жҠҘдҝ®еҚ•еҸ·пјҡ{{ item.id }}</view>
							</view>

							<view
								class="order__item__content tn-flex tn-flex-direction-row tn-flex-nowrap tn-flex-col-center tn-flex-row-center">
								<view class="order__item__content__image" style="margin-left: -10px;">
									<image src="/static/tabbar/i2.png" mode="aspectFill"></image>
								</view>
								<view class="order__item__content__title">
									<text
										class="order__item__content__info__price__cons">жҠҘдҝ®зұ»еһӢпјҡ{{ item.repairClass || 'жңӘзҹҘзұ»еһӢ' }}</text>
									<br>
									<text
										class="order__item__content__info__price__cons">ж•…йҡңжҸҸиҝ°пјҡ{{ item.note || 'ж— жҸҸиҝ°' }}</text>
									<br>
									<text
										class="order__item__content__info__price__cons">жҠҘдҝ®ж—¶й—ҙпјҡ{{ item.time || 'жңӘзҹҘж—¶й—ҙ' }}</text>
								</view>
							</view>

							<view
								class="order__item__operation tn-flex tn-flex-direction-row tn-flex-nowrap tn-flex-col-center tn-flex-row-between">
								<view class="order__item__operaation__left">
									<text class="order__item__operaation__left--text"></text>
								</view>
								<view
									class="order__item__operation__right tn-flex tn-flex-direction-row tn-flex-nowrap tn-flex-col-center tn-flex-row-right">
									<view class="order__item__operation__right__button">
										<tn-button shadow shape="round" fontColor="tn-color-white"
											backgroundColor="tn-bg-blue" :fontSize="24" height="auto"
											padding="10rpx 18rpx">
											жҹҘзңӢиҜҰз»Ҷ</tn-button>
									</view>
								</view>
							</view>
						</view>
						<!-- еә•йғЁе®үе…Ёи·қзҰ» -->
						<view class="tn-padding-bottom"></view>
					</scroll-view>
				</swiper-item>
			</swiper>
		</view>
	</view>
</template>

<script>
	import templatePageMixin from '@/libs/mixin/template_page_mixin.js'

	export default {
		name: 'template-order',
		mixins: [templatePageMixin],
		data() {
			return {
				ongoingRepairs: [], // иҝӣиЎҢдёӯжҠҘдҝ®еҚ•
				completedRepairs: [], // е·Іе®ҢжҲҗжҠҘдҝ®еҚ•
				user: {}, // еҪ“еүҚзҷ»еҪ•з”ЁжҲ·дҝЎжҒҜ
				list: [{
					name: 'иҝӣиЎҢдёӯ'
				}, {
					name: 'е·Іе®ҢжҲҗ'
				}], // ж ҮзӯҫеҲ—иЎЁ
				tabsIndex: 0, // ж ҮзӯҫеҪ“еүҚзҙўеј•
				swiperIndex: 0, // swiperеҪ“еүҚзҙўеј•
				scrollViewHeight: 0, // scroll-viewеҠЁжҖҒй«ҳеәҰ
				showPassword: false // еҶ—дҪҷеӯ—ж®өпјҲдҝқз•ҷе…је®№пјү
			}
		},
		// йЎөйқўеҠ иҪҪж—¶еҲқе§ӢеҢ–
		onLoad() {
			this.fetchData()
		},
		// йЎөйқўжёІжҹ“е®ҢжҲҗеҗҺи®Ўз®—й«ҳеәҰ
		onReady() {
			this.$nextTick(() => {
				this.calcScrollViewHeight()
			})
		},
		// йЎөйқўжҳҫзӨәж—¶еҲ·ж–°ж•°жҚ®пјҲе…је®№зӣҙжҺҘиҝӣе…ҘйЎөйқўпјү
		onShow() {
			// йҒҝе…ҚжңӘзҷ»еҪ•ж—¶йҮҚеӨҚи·іиҪ¬
			const userStr = uni.getStorageSync('user')
			if (userStr) {
				this.user = JSON.parse(userStr)
				this.fetchData()
			}
		},
		// еә•йғЁеҜјиҲӘеҲҮжҚўж—¶и§ҰеҸ‘зҡ„ж ёеҝғж–№жі•пјҲindex.vueдјҡи°ғз”Ёпјү
		repair_reportOnShow() {
			console.log("repair_reportOnShow и§ҰеҸ‘пјҢйҮҚж–°еҠ иҪҪж•°жҚ®")
			// ејәеҲ¶еҲ·ж–°ж•°жҚ® + йҮҚж–°и®Ўз®—й«ҳеәҰ
			this.fetchData()
			this.calcScrollViewHeight()
		},
		methods: {
			// ж–°еўһпјҡеҝ…йЎ»е’Ң index.vue дёӯи°ғз”Ёзҡ„ж–№жі•еҗҚе®Ңе…ЁдёҖиҮҙ
			repair_reportOnShow() {
				console.log("repair_reportOnShow жү§иЎҢ");
				// еҸҜиЎҘе……з»„д»¶йңҖиҰҒзҡ„еҲқе§ӢеҢ–йҖ»иҫ‘пјҢжҜ”еҰӮеҠ иҪҪжҠҘдҝ®еҲ—иЎЁгҖҒеҲ·ж–°ж•°жҚ®зӯү
				// зӨәдҫӢпјҡthis.loadRepairList();
			},
			// и·іиҪ¬иҜҰжғ…йЎөпјҲжҗәеёҰи®ўеҚ•IDпјү
			tn(e) {
				uni.navigateTo({
					url: e
				});
			},
			// ж ҮзӯҫеҲҮжҚўиҒ”еҠЁswiper
			tabsChange(index) {
				this.swiperIndex = index
				this.tabsIndex = index
			},
			// swiperж»‘еҠЁж—¶иҒ”еҠЁж ҮзӯҫдҪҚзҪ®
			swiperTransition(event) {
				if (this.$refs.tabs && typeof this.$refs.tabs.setDx === 'function') {
					this.$refs.tabs.setDx(event.detail.dx)
				}
			},
			// swiperж»‘еҠЁз»“жқҹеҗҺеҗҢжӯҘж Үзӯҫзҙўеј•
			swiperAnimationFinish(event) {
				const current = event.detail.current
				if (this.$refs.tabs && typeof this.$refs.tabs.setFinishCurrent === 'function') {
					this.$refs.tabs.setFinishCurrent(current)
				}
				this.swiperIndex = current
				this.tabsIndex = current
			},
			// и®Ўз®—scroll-viewй«ҳеәҰпјҲж ёеҝғи§ЈеҶіжәўеҮәй—®йўҳпјү
			calcScrollViewHeight() {
				uni.getSystemInfo({
					success: (sysInfo) => {
						// еҹәзЎҖй«ҳеәҰи®Ўз®—пјҡеұҸе№•й«ҳеәҰ - еҜјиҲӘж Ҹ - ж Үзӯҫж Ҹ - е®үе…Ёи·қзҰ»
						const navHeight = this.vuex_custom_bar_height || 0 // иҮӘе®ҡд№үеҜјиҲӘж Ҹй«ҳеәҰ
						const tabsHeight = sysInfo.windowWidth / 750 * 88 // ж Үзӯҫж Ҹй«ҳеәҰпјҲ88rpxиҪ¬pxпјү
						const safeBottom = sysInfo.safeAreaInsets.bottom || 20 // еә•йғЁе®үе…Ёи·қзҰ»

						// жңҖз»Ҳscroll-viewй«ҳеәҰ
						this.scrollViewHeight = sysInfo.windowHeight - navHeight - tabsHeight - safeBottom - 40
						console.log("scrollViewй«ҳеәҰи®Ўз®—е®ҢжҲҗпјҡ", this.scrollViewHeight)
					},
					fail: (err) => {
						console.error("иҺ·еҸ–зі»з»ҹдҝЎжҒҜеӨұиҙҘпјҡ", err)
						// е…ңеә•й«ҳеәҰ
						this.scrollViewHeight = 500
					}
				})
			},
			// ж ёеҝғпјҡиҜ·жұӮжҠҘдҝ®еҚ•ж•°жҚ®пјҲе…је®№з”ЁжҲ·/з»ҙдҝ®дәәе‘ҳиә«д»Ҫпјү
			fetchData() {
				// 1. ж ЎйӘҢзҷ»еҪ•зҠ¶жҖҒ
				const userStr = uni.getStorageSync('user')
				if (!userStr) {
					uni.showToast({
						title: 'иҜ·е…Ҳзҷ»еҪ•',
						icon: 'none',
						duration: 1500
					})
					uni.navigateTo({
						url: '/pages/login/login'
					})
					return
				}

				// 2. и§Јжһҗз”ЁжҲ·дҝЎжҒҜ
				this.user = JSON.parse(userStr)
				// е…је®№з”ЁжҲ·/з»ҙдҝ®дәәе‘ҳзҡ„жҹҘиҜўе…ій”®еӯ—пјҲеӯҰеҸ·/е·ҘеҸ·пјү
				const queryKey = this.user.identityType === 'user' ?
					this.user.userNumber :
					this.user.number

				// 3. ж ЎйӘҢз”ЁжҲ·дҝЎжҒҜе®Ңж•ҙжҖ§
				if (!queryKey) {
					uni.showToast({
						title: 'з”ЁжҲ·дҝЎжҒҜејӮеёёпјҢзјәе°‘еӯҰеҸ·/е·ҘеҸ·',
						icon: 'none'
					})
					return
				}

				// 4. жҳҫзӨәеҠ иҪҪжҸҗзӨә
				uni.showLoading({
					title: 'еҠ иҪҪдёӯ...',
					mask: true
				})

				// 5. еҠЁжҖҒжӢјжҺҘиҜ·жұӮең°еқҖпјҲеҢәеҲҶз”ЁжҲ·/з»ҙдҝ®дәәе‘ҳпјү
				const apiUrl = this.user.identityType === 'user' ?
					`http://localhost:8099/warranty/searchByUserNumber/${queryKey}` :
					`http://localhost:8099/warranty/searchByRepairmanNumber/${queryKey}`

				// 6. еҸ‘иө·иҜ·жұӮ
				uni.request({
					url: apiUrl,
					method: 'GET',
					timeout: 10000, // и¶…ж—¶ж—¶й—ҙ
					success: (res) => {
						uni.hideLoading()
						// жҺҘеҸЈжҲҗеҠҹиҝ”еӣһ
						if (res.data && res.data.code === '0') {
							const dataList = res.data.data || []
							// жё…з©әж—§ж•°жҚ®
							this.ongoingRepairs = []
							this.completedRepairs = []
							// еҲҶзұ»и®ўеҚ•пјҲе…је®№дёҚеҗҢзҡ„зҠ¶жҖҒеҖјпјү
							dataList.forEach(item => {
								const state = (item.state || '').trim()
								if (['з»ҙдҝ®иҝӣиЎҢдёӯ', 'иҝӣиЎҢдёӯ', 'еӨ„зҗҶдёӯ', 'еҫ…з»ҙдҝ®'].includes(state)) {
									this.ongoingRepairs.push(item)
								} else if (['з»ҙдҝ®е·Іе®ҢжҲҗ', 'е·Іе®ҢжҲҗ', 'е®Ңз»“', 'е·ІйӘҢж”¶'].includes(state)) {
									this.completedRepairs.push(item)
								}
							})
							console.log("ж•°жҚ®еҠ иҪҪе®ҢжҲҗпјҡ", {
								иҝӣиЎҢдёӯ: this.ongoingRepairs.length,
								е·Іе®ҢжҲҗ: this.completedRepairs.length
							})
						} else {
							// жҺҘеҸЈиҝ”еӣһејӮеёёпјҲж— ж•°жҚ®/дёҡеҠЎй”ҷиҜҜпјү
							this.ongoingRepairs = []
							this.completedRepairs = []
							uni.showToast({
								title: res.data?.msg || 'жҡӮж— жҠҘдҝ®ж•°жҚ®',
								icon: 'none',
								duration: 1500
							})
						}
					},
					fail: (err) => {
						uni.hideLoading()
						console.error("жҠҘдҝ®еҚ•иҜ·жұӮеӨұиҙҘпјҡ", err)
						uni.showToast({
							title: 'зҪ‘з»ңй”ҷиҜҜпјҢеҠ иҪҪеӨұиҙҘ',
							icon: 'none',
							duration: 1500
						})
					}
				})
			}
		}
	}
</script>

<style lang="scss" scoped>
	// йЎөйқўеҹәзЎҖж ·ејҸ
	.template-order {
		background-color: #F5F7FA;
		min-height: 100vh;
	}

	// еҜјиҲӘж ҸеҚ дҪҚпјҲйҒҝе…ҚеҶ…е®№иў«еҜјиҲӘж ҸйҒ®жҢЎпјү
	.nav-placeholder {
		width: 100%;
		background-color: #fff;
	}

	// и®ўеҚ•е®№еҷЁпјҲжөҒејҸеёғеұҖпјү
	.order__container {
		width: 100%;
		height: calc(100vh - var(--custom-nav-height, 0px));
		display: flex;
		flex-direction: column;
	}

	// ж Үзӯҫж Ҹе®№еҷЁ
	.order__tabs-wrap {
		width: 100%;
		z-index: 10;
		box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.05);
	}

	.order__tabs {
		width: 100%;
	}

	// Swiperе®№еҷЁпјҲеҚ ж»Ўеү©дҪҷй«ҳеәҰпјү
	.order__swiper {
		flex: 1;
		width: 100%;
	}

	.order__swiper__item {
		width: 100%;
		height: 100%;
	}

	// ж»ҡеҠЁеҢәеҹҹпјҲеҠЁжҖҒй«ҳеәҰпјү
	.order__scroll-view {
		width: 100%;
		padding-bottom: 20rpx;
	}

	// и®ўеҚ•еҚЎзүҮж ·ејҸ
	.order__item {
		margin: 20rpx;
		padding: 36rpx 26rpx;
		background-color: #FFFFFF;
		border-radius: 15rpx;
		box-shadow: 0rpx 0rpx 50rpx 0rpx rgba(0, 0, 0, 0.07);

		// дҝ®еӨҚз¬¬дёҖдёӘеҚЎзүҮйЎ¶йғЁй—ҙи·қ
		&:first-child {
			margin-top: 20rpx;
		}

		// и®ўеҚ•еӨҙйғЁпјҲеҚ•еҸ·пјү
		&__head {
			margin-bottom: 20rpx;

			&__title {
				font-weight: bold;
				line-height: normal;
				font-size: 32rpx;
				color: #333;
			}
		}

		// и®ўеҚ•еҶ…е®№пјҲзұ»еһӢ/жҸҸиҝ°/ж—¶й—ҙпјү
		&__content {
			margin-bottom: 30rpx;

			&__image {
				margin-right: 20rpx;

				image {
					width: 140rpx;
					height: 140rpx;
					border-radius: 10rpx;
				}
			}

			&__title {
				height: auto;
				min-height: 50px;
				padding-right: 40rpx;
				font-size: 28rpx;
				color: #333;
				line-height: 1.5;
			}
		}

		// ж“ҚдҪңжҢүй’®еҢәеҹҹ
		&__operation {
			margin-top: 10rpx;
		}
	}

	// з©әж•°жҚ®ж ·ејҸ
	.empty-data {
		padding: 60rpx 20rpx;
		text-align: center;
		min-height: 400rpx;
		display: flex;
		flex-direction: column;
